CREATE TABLE policies_to_security_requirements
(
id serial NOT NULL,
policy_id integer NOT NULL,
security_requirement_id integer DEFAULT NULL,
CONSTRAINT pk_policies_to_security_requirements PRIMARY KEY (id)
, CONSTRAINT fk_policies_to_security_requirements_to_policies FOREIGN KEY (policy_id) REFERENCES policies (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
, CONSTRAINT fk_policies_to_security_requirements_to_security_requirements FOREIGN KEY (security_requirement_id) REFERENCES security_requirements (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
);
CREATE INDEX i_policies_to_security_requirements_policy_id ON policies_to_security_requirements (policy_id);
CREATE INDEX i_policies_to_security_requirements_security_requirement_id ON policies_to_security_requirements (security_requirement_id);
CREATE INDEX i_pk_policies_to_security_requirements ON policies_to_security_requirements (id);
